-- FSI_DEMO_DB.WEALTH_MANAGEMENT.MARKET_COMMENTARY

CREATE OR REPLACE TABLE FSI_DEMO_DB.WEALTH_MANAGEMENT.MARKET_COMMENTARY (

    COMMENTARY_ID VARCHAR(20) NOT NULL,
    PUBLISH_DATE DATE,
    AUTHOR_ID VARCHAR(20),
    AUTHOR_NAME VARCHAR(100),
    TITLE VARCHAR(300),
    CONTENT VARCHAR(16777216),
    SUMMARY VARCHAR(1000),
    ASSET_CLASSES_COVERED VARCHAR(200),
    MARKET_OUTLOOK VARCHAR(30),
    KEY_THEMES VARCHAR(16777216),
    RECOMMENDATIONS VARCHAR(16777216),
    TARGET_AUDIENCE VARCHAR(50),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (COMMENTARY_ID)

);

